from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["mobile-pc-pairing-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Mobile ↔ PC Pairing</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button,input,select,textarea{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:85px}.url{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px;word-break:break-all}.warn{border-left-color:var(--warn)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>Mobile ↔ PC Pairing</h1><p class="muted">Liga o APK ao PC automaticamente em casa por IP local e prepara acesso da rua por URL remoto seguro.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/today-ready'" class="dark">Today Ready</button><button onclick="manifest()">Manifest</button><button onclick="pair()">Criar pairing local</button></div></section><section class="panel"><h2>URLs para o APK tentar</h2><div id="urls" class="grid"></div></section><section class="panel"><h2>Acesso remoto da rua</h2><div class="grid"><select id="provider"><option>cloudflare_tunnel</option><option>tailscale</option><option>ngrok</option><option>manual_public_url</option></select><input id="publicUrl" placeholder="https://teu-tunnel.example.com"/></div><div class="buttons"><button onclick="remotePlan()">Criar plano remoto</button></div><p class="muted">Sem URL remoto/túnel, o telemóvel só liga dentro da rede de casa. Da rua precisa HTTPS remoto aprovado.</p></section><section class="panel"><h2>Guardar material remoto no Vault</h2><input id="profileId" style="width:100%" placeholder="remote-profile-..."/><textarea id="material" placeholder="Cola aqui material remoto apenas se quiseres guardar no Vault local do PC."></textarea><button onclick="storeMaterial()">Guardar no Vault</button></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const order=x?.mobile_should_try_in_order||x?.manifest?.mobile_should_try_in_order||x?.connection_manifest?.mobile_should_try_in_order||[];qs('#urls').innerHTML=order.map(i=>`<div class="url ${i.mode==='remote'?'warn':''}"><b>${esc(i.mode)}</b><br>${esc(i.url)}</div>`).join(''); const profile=x?.remote_profile; if(profile?.remote_profile_id) qs('#profileId').value=profile.remote_profile_id}async function manifest(){show(await api('/api/mobile-pc-pairing/connection-manifest'))}async function pair(){show(await api('/api/mobile-pc-pairing/create-pairing-session',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({port:8787,ttl_minutes:60})}))}async function remotePlan(){show(await api('/api/mobile-pc-pairing/create-remote-access-plan',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({provider:qs('#provider').value,public_url:qs('#publicUrl').value,project_id:'GOD_MODE'})}))}async function storeMaterial(){show(await api('/api/mobile-pc-pairing/store-remote-material',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({remote_profile_id:qs('#profileId').value,material:qs('#material').value,label:'remote access material'})}))}manifest()</script></body></html>
"""


@router.get('/app/mobile-pc-pairing', response_class=HTMLResponse)
async def mobile_pc_pairing_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/connect-phone', response_class=HTMLResponse)
async def connect_phone_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
